<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ONBOOT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=yes                   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 开机自动启用</span></span>
